class Message {
  final String id;
  final String text;

  const Message(this.id, this.text);

  Map<String, dynamic> toJson() => <String, dynamic>{'id': id, 'text': text};

  factory Message.fromJson(Map<String, dynamic> value) {
    return Message(value['id'] as String, value['text'] as String);
  }
}

