class VarintResult {
  final int value;
  final int bytesRead;

  const VarintResult(this.value, this.bytesRead);
}

List<int> encodeVarint(int value) {
  if (value < 0) throw ArgumentError.value(value, 'value');
  return <int>[value & 0x7f];
}

VarintResult decodeVarint(List<int> bytes, [int offset = 0]) {
  if (offset < 0 || offset >= bytes.length) {
    throw const FormatException('truncated varint');
  }
  return VarintResult(bytes[offset] & 0x7f, 1);
}

