import '../lib/envelope_codec.dart';
import '../lib/message.dart';
import '../lib/varint.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  check(encodeVarint(12).single == 12, 'small varint encoding');
  final encoded = encodeEnvelope(const Message('a', 'ready'));
  final decoded = decodeEnvelopes(encoded);
  check(decoded.length == 1, 'one small envelope');
  check(decoded.single.id == 'a' && decoded.single.text == 'ready', 'small message round trip');
  print('public tests passed');
}
